@@ -0,0 +1,14 @@
+{
+  "name": "ech_default_one",
+  "description": "ECH with no parameter defaults to erasing 1 character at cursor",
+  "initial_size": [80, 24],
+  "input_bytes_hex": "41421b5b31471b5b58",
+  "comment": "Print AB (cursor at col 2), CHA(1) to col 0, ECH (default=1) erases col 0, cursor stays at col 0",
+  "expected": {
+    "cursor": { "row": 0, "col": 0 },
+    "cells": [
+      { "row": 0, "col": 0, "char": " " },
+      { "row": 0, "col": 1, "char": "B" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "scroll_down_multi",
+  "description": "CSI 2 T scrolls down by 2 lines",
+  "initial_size": [5, 4],
+  "input_bytes_hex": "411b5b323b314842 1b5b333b314843 1b5b343b314844 1b5b325458",
+  "comment": "Print A at (0,0), B at (1,0), C at (2,0), D at (3,0) cursor->(3,1). CSI 2 T scrolls down 2 lines. C and D scroll off bottom. A->(2,0), B->(3,0). Cursor stays at (3,1). X printed at (3,1) overwriting B's col 1, cursor->(3,2).",
+  "expected": {
+    "cursor": { "row": 3, "col": 2 },
+    "cells": [
+      { "row": 2, "col": 0, "char": "A" },
+      { "row": 3, "col": 0, "char": "B" },
+      { "row": 3, "col": 1, "char": "X" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "scroll_up_multi",
+  "description": "CSI 2 S scrolls up by 2 lines",
+  "initial_size": [5, 4],
+  "input_bytes_hex": "411b5b323b314842 1b5b333b314843 1b5b343b314844 1b5b325358",
+  "comment": "Print A at (0,0), CUP(2,1) B at (1,0), CUP(3,1) C at (2,0), CUP(4,1) D at (3,0) cursor->(3,1). CSI 2 S scrolls up 2 lines. A and B scroll off. C->(0,0), D->(1,0). Cursor stays at (3,1). X printed at (3,1), cursor->(3,2).",
+  "expected": {
+    "cursor": { "row": 3, "col": 2 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "C" },
+      { "row": 1, "col": 0, "char": "D" },
+      { "row": 3, "col": 1, "char": "X" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "overwrite_at_right_margin",
+  "description": "Printing at right margin overwrites the cell but does not advance to next line yet",
+  "initial_size": [10, 5],
+  "input_bytes_hex": "4142434445464748494a1b5b3130475a",
+  "comment": "Fill 10 cols (pending wrap), CHA(10) to col 9 (clears pending wrap), print Z at col 9 sets pending wrap again; cursor stays at (0,9)",
+  "expected": {
+    "cursor": { "row": 0, "col": 9 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A" },
+      { "row": 0, "col": 8, "char": "I" },
+      { "row": 0, "col": 9, "char": "Z" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "pending_wrap_cleared_by_cursor_move",
+  "description": "Cursor movement (CUB) clears pending wrap without wrapping to next line",
+  "initial_size": [10, 5],
+  "input_bytes_hex": "4142434445464748494a1b5b4458",
+  "comment": "Print ABCDEFGHIJ (fills 10 cols, pending wrap), CUB(1) clears wrap and moves to col 8, print X overwrites col 8",
+  "expected": {
+    "cursor": { "row": 0, "col": 9 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A" },
+      { "row": 0, "col": 8, "char": "X" },
+      { "row": 0, "col": 9, "char": "J" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "wrap_at_margin",
+  "description": "Printing at right margin sets pending wrap; next print wraps to new line",
+  "initial_size": [10, 5],
+  "input_bytes_hex": "4142434445464748494a4b",
+  "comment": "Print ABCDEFGHIJ (fills 10 cols), then K wraps to row 1 col 0; cursor at (1,1)",
+  "expected": {
+    "cursor": { "row": 1, "col": 1 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A" },
+      { "row": 0, "col": 9, "char": "J" },
+      { "row": 1, "col": 0, "char": "K" }
+    ]
+  }
+}
